            default = {
              type = 0
            }
          },
          interrupt_if = {
            ui_label = "Interrupt If",
            full_description = "Interrupt the channel if the condition is true.",
            default = {
              value = {
                oneof_kind = "gcdIsReady",
                gcd_is_ready = {

                }
              }
            }
          },
          allow_recast = {
            ui_label = "Recast",
            full_description = "If checked, interrupts of this channel will recast the spell.",
            default = false
          }
        }
      }
    },
